INSERT INTO public.wiki_pages (id, room_id, title, content, parent_id, created_at, updated_at) VALUES ('a2e40f44-1460-45bc-93e9-c4c3cd09fd8c', 'c3497459-c4bf-4a9e-a01e-032f1a3f4df0', 'Astralismo', '<p><img src="data:image/png;base64,"></p><p><br></p><p><strong><u>Astralismo</u></strong></p><p><br></p><p>El Astralismo es una religión ficticia basada en una mitología antigua que narra la historia de los dioses primordiales Æternum, Ærebor y Hecævia. Esta tradición enfatiza el misterio, la magia y la comprensión multifacética de la verdad, centrándose en Hecævia como intermediaria entre la luz y la oscuridad, sin alinearse con ninguno de los lados en su conflicto divino.</p><p><br></p><p><strong><u>Doctrina</u></strong></p><p>Astralismo se centra en Hecævia, la diosa de la Magia y el intermediario entre la Luz y la Oscuridad. Esta religión valora el misterio, la magia y la comprensión de que la verdad a menudo tiene múltiples facetas. Los seguidores respetan tanto a Æternum como a Ærebor, pero no toman partido en su conflicto.</p><h2><br></h2><p><u>Estructura</u></p><ul><li>Oráculo de las Estrellas: Un líder espiritual que interpreta los signos y enseñanzas de Hecævia.</li><li>Santuarios del Velo: Lugares de culto místicos bajo cielos estrellados, a menudo ubicados en entornos tranquilos y aislados.</li><li>Videntes y Escribas: Místicos y eruditos que estudian las estrellas, la magia y los textos antiguos para obtener una comprensión más profunda del cosmos.</li><li>Enseñanzas: Enfatizan la sabiduría, la magia y la búsqueda del conocimiento. Las escrituras incluyen "Las Lágrimas de Hecævia" y "Los Enigmas de la Creación."</li></ul><p><br></p><p><u>Prácticas</u></p><ul><li><strong>Observación de las Estrellas:</strong> Los seguidores pasan noches observando las estrellas, creyendo que son las lágrimas de Hecævia y fuentes de sabiduría.</li><li><strong>Magia y Alquimia:</strong> Practican y estudian la magia como un medio para entender y conectarse con lo divino.</li><li><strong>Festivales:</strong> "Noche del Velo," celebrando la influencia de Hecævia, donde los seguidores se reúnen bajo las estrellas para compartir historias, lanzar hechizos y buscar visiones.</li></ul><p><br></p>', '383bcbf6-da3c-4829-afe0-9152197a4cf4', '2025-08-31 15:29:41.32193', '2025-08-31 15:33:45.138');

